// ============================================================
// CONFIG
// ⚠️ URL PAP.fr: aller sur pap.fr → recherche locations
//    Gif-sur-Yvette → copier l'URL de résultats → ajouter .rss
// ============================================================
const PAP_RSS_URL = 'https://www.pap.fr/annonce/locations-appartement-maison-gif-sur-yvette-g37752-gg37752a.rss?nb_pieces_min=2&nb_pieces_max=3&prix_max=1200';
const PRIX_MAX      = 1200;
const PIECES_MIN    = 2;
const PIECES_MAX    = 3;
const HORIZON_JOURS = 7;
const TABLE_NAME    = 'immo_annonces_gif_yvette';

const NOCO_URL   = $env.NOCODB_INTERNAL_URL || 'http://nocodb:8080';
const NOCO_TOKEN = $env.NOCODB_API_TOKEN;
const BASE_ID    = $env.NOCODB_CF_BASE_ID;
const TG_TOKEN   = $env.TELEGRAM_OPENCLAW_BOT_TOKEN;
const TG_CHAT    = $env.TELEGRAM_OPENCLAW_GROUP_ID;
const TG_TOPIC   = parseInt($env.TELEGRAM_OPENCLAW_TOPIC_IDS_RECHERCHE || '6');

if (!NOCO_TOKEN || !BASE_ID) {
  throw new Error('NOCODB_API_TOKEN ou NOCODB_CF_BASE_ID manquant dans les env vars n8n');
}

// ============================================================
// HELPERS NocoDB
// ============================================================
const nH = { 'xc-token': NOCO_TOKEN, 'Content-Type': 'application/json' };

async function nGet(path) {
  const r = await fetch(`${NOCO_URL}${path}`, { headers: nH });
  if (!r.ok) throw new Error(`NocoDB GET ${path} → ${r.status}`);
  return r.json();
}

async function nPost(path, body) {
  const r = await fetch(`${NOCO_URL}${path}`, {
    method: 'POST', headers: nH, body: JSON.stringify(body)
  });
  if (!r.ok) throw new Error(`NocoDB POST ${path} → ${r.status}: ${(await r.text()).substring(0, 200)}`);
  return r.json();
}

// ============================================================
// AUTO-INIT: trouver ou créer la table NocoDB
// tableId mis en cache dans staticData (persiste entre runs)
// ============================================================
const sd = $workflow.staticData;
let tableId = sd.immoTableId;

if (!tableId) {
  const tablesResp = await nGet(`/api/v1/db/meta/projects/${BASE_ID}/tables`);
  const existing = (tablesResp.list || []).find(t => t.table_name === TABLE_NAME);

  if (existing) {
    tableId = existing.id;
  } else {
    const created = await nPost(`/api/v1/db/meta/projects/${BASE_ID}/tables`, {
      table_name: TABLE_NAME,
      title: 'Immo — Gif-sur-Yvette',
      columns: [
        { title: 'ext_id',       uidt: 'SingleLineText', column_name: 'ext_id' },
        { title: 'source',       uidt: 'SingleLineText', column_name: 'source' },
        { title: 'titre',        uidt: 'SingleLineText', column_name: 'titre' },
        { title: 'prix',         uidt: 'Currency',       column_name: 'prix' },
        { title: 'pieces',       uidt: 'Number',         column_name: 'pieces' },
        { title: 'lien',         uidt: 'URL',            column_name: 'lien' },
        { title: 'description',  uidt: 'LongText',       column_name: 'description' },
        { title: 'publie_le',    uidt: 'DateTime',       column_name: 'publie_le' },
        { title: 'premiere_vue', uidt: 'DateTime',       column_name: 'premiere_vue' },
        {
          title: 'statut', uidt: 'SingleSelect', column_name: 'statut',
          meta: { options: [
            { title: 'nouveau',  color: '#36BFFF' },
            { title: 'vu',       color: '#FFA500' },
            { title: 'contacté', color: '#00C9A7' },
            { title: 'ignoré',   color: '#999999' }
          ]}
        }
      ]
    });
    tableId = created.id;
    console.log(`Table créée: ${TABLE_NAME} → ${tableId}`);
  }

  sd.immoTableId = tableId;
}

// ============================================================
// FETCH PAP.fr RSS
// ============================================================
const getField = (block, tag) => {
  const m = block.match(new RegExp(`<${tag}[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/${tag}>`, 'i'));
  return m ? m[1].trim() : '';
};

const HORIZON_MS = HORIZON_JOURS * 24 * 60 * 60 * 1000;
const now = Date.now();
const candidates = [];

try {
  const papResp = await fetch(PAP_RSS_URL, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      'Accept': 'application/rss+xml, application/xml, text/xml, */*'
    }
  });
  if (!papResp.ok) throw new Error(`PAP.fr HTTP ${papResp.status}`);
  const xml = await papResp.text();

  const itemRe = /<item>([\s\S]*?)<\/item>/g;
  let m;
  while ((m = itemRe.exec(xml)) !== null) {
    const block = m[1];
    const title  = getField(block, 'title');
    const link   = getField(block, 'link') || getField(block, 'guid');
    const id     = getField(block, 'guid') || link;
    const pubStr = getField(block, 'pubDate');
    const desc   = getField(block, 'description').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 400);

    if (pubStr && (now - new Date(pubStr).getTime()) > HORIZON_MS) continue;

    const priceM = (title + ' ' + desc).match(/(\d[\d\s]{0,5})\s*€/);
    const prix   = priceM ? parseInt(priceM[1].replace(/\s/g, '')) : null;
    if (prix && prix > PRIX_MAX) continue;

    const roomM  = (title + ' ' + desc).match(/(\d)\s*(?:pièces?|ch\.?\s|chambres?)/i);
    const pieces = roomM ? parseInt(roomM[1]) : null;
    if (pieces !== null && (pieces < PIECES_MIN || pieces > PIECES_MAX + 1)) continue;

    candidates.push({
      ext_id:      `pap_${id}`,
      source:      'pap.fr',
      titre:       title,
      prix,
      pieces,
      lien:        link,
      description: desc,
      publie_le:   pubStr ? new Date(pubStr).toISOString() : new Date().toISOString()
    });
  }
} catch (e) {
  await fetch(`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: TG_CHAT, message_thread_id: TG_TOPIC, text: `⚠️ immo-finder: erreur PAP.fr\n${e.message}`, parse_mode: 'HTML' })
  });
}

if (candidates.length === 0) {
  return [{ json: { sent: false, count: 0, reason: 'aucun candidat après filtrage' } }];
}

// ============================================================
// DÉDUPLICATION via NocoDB (vérification par ext_id)
// ============================================================
const newItems = [];

for (const item of candidates) {
  const eid = encodeURIComponent(item.ext_id);
  const check = await nGet(`/api/v2/tables/${tableId}/records?where=(ext_id,eq,${eid})&limit=1`);
  if ((check.list || []).length === 0) newItems.push(item);
}

if (newItems.length === 0) {
  console.log(`Aucune nouvelle annonce. ${candidates.length} candidates déjà vues.`);
  return [{ json: { sent: false, count: 0, candidates: candidates.length } }];
}

// ============================================================
// INSERT nouvelles annonces dans NocoDB
// ============================================================
const now_iso = new Date().toISOString();
for (const item of newItems) {
  await nPost(`/api/v2/tables/${tableId}/records`, {
    ...item, premiere_vue: now_iso, statut: 'nouveau'
  });
}

// ============================================================
// TELEGRAM
// ============================================================
const header = `🏠 <b>Gif-sur-Yvette — ${newItems.length} nouvelle(s) annonce(s)</b>\n` +
  `2-3 ch · max 1 200€ · &lt;${HORIZON_JOURS}j · PAP.fr\n`;

const lines = newItems.map(i => {
  const px = i.prix   ? ` · <b>${i.prix}€</b>` : '';
  const rm = i.pieces ? ` · ${i.pieces}p`       : '';
  return `• <a href="${i.lien}">${i.titre}</a>${px}${rm}`;
});

const chunks = [];
let current = header + '\n';
for (const line of lines) {
  if ((current + line + '\n').length > 4000) { chunks.push(current); current = ''; }
  current += line + '\n';
}
if (current.trim()) chunks.push(current);

for (const chunk of chunks) {
  await fetch(`https://api.telegram.org/bot${TG_TOKEN}/sendMessage`, {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: TG_CHAT, message_thread_id: TG_TOPIC, text: chunk, parse_mode: 'HTML', disable_web_page_preview: false })
  });
}

return [{ json: { sent: true, count: newItems.length, items: newItems.map(i => i.titre) } }];
